#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
ll gcd(ll a,ll b)
{
    return ((b==0)?(a):(gcd(b,a%b)));
}
CI MAXN=1e3+5;
int n,f[MAXN][MAXN],m;
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
    //Read
    n=read(),m=read();
    for(int i=1;i<=n;++i)
    {
        f[i][i]=read();
    }
    //Dynamic Programming
    for(int i=n;i;--i)
    {
        for(int j=i+1;j<=n;++j)
        {
            f[i][j]=gcd(f[i][i],f[i+1][j]);
        }
    }
    for(int i=1;i<=m;++i)
    {
        int l=read(),r=read();
        write(f[l][r]);
        putchar('\n');
    }    
	return false;
}
